+            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
+                <button class="page-link" @onclick="@(() => ChangePage(Page + 1))" disabled="@(Page >= TotalPages)">
+                    Next
+                </button>
+            </li>
